{
  "name": "DC Senior Centers",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits for general DC senior centers; many operate on voluntary contributions, sliding scale fees, or are free for DC residents age 60+. Specific programs like employment training require income <125% federal poverty level. Medicaid-related services cap at 300% SSI ($2,982 individual in 2026) or medically needy limits ($856.90 individual, $902 household of 2+ in 2026).[2][1]",
    "asset_limits": "Not applicable for general senior centers. Medicaid long-term care services limit resources to $4,000 (individual) or $6,000 (couple); home equity ≤$1,130,000 exempt if intent to return or spouse/minor/disabled child resides there.[2][3]",
    "other_requirements": ["DC resident", "Able to complete daily living activities independently or with personal care assistant (no dementia/Alzheimer's diagnosis for some centers)", "US citizen or eligible immigration status for Medicaid-linked services", "Nursing facility level of care for waiver programs (assessed via interRAI tool, score ≥9 points on ADLs/cognition/behavior)"]
  },
  "benefits": {
    "type": "service",
    "value": "Social, recreational, nutritional, health promotion activities (e.g., free meals, food commodities, health screenings like blood pressure/blood sugar, nutritional counseling, mental health support, education classes, exercise, social services case management); hours vary by center (e.g., Mon/Thu 10am-4pm, Tue/Wed/Fri 10am-2pm at SOME); no fixed dollar amount, often free or low-cost.[4][9][5]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["In-person at centers (e.g., SOME at 1395 Aspen St. NW, Washington, DC 20012; Vida Senior Centers locations)", "Phone: (202) 724-7000 for employment program info", "Contact Aging and Disability Resource Center (ADRC) via D.C. Office on Aging for referrals", "Email for specific programs"],
    "processing_time": "Not specified; typically immediate intake at centers upon eligibility screening",
    "waitlist": null,
    "forms": ["No specific form named; intake assessment at centers or ADRC"],
    "documents": ["Proof of DC residency (ID, utility bill)", "Proof of age (ID/birth certificate)", "Income proof if applying for means-tested services", "Medical records for functional assessments if needed"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "District of Columbia residents only",
    "regional_variations": "Multiple providers/centers with varying hours/services (e.g., SOME in NW DC excludes dementia; Vida focuses on Hispanic seniors with Spanish services; citywide network via D.C. Office on Aging and ADRC)",
    "offices_or_providers": ["SOME Senior Services (1395 Aspen St. NW)", "Vida Senior Centers (multiple sites for Hispanic seniors)", "D.C. Office on Aging ADRC", "Various community centers across DC"]
  },
  "official_source": "https://dcoa.dc.gov/ (D.C. Office on Aging primary site; specific centers via provider sites)",
  "gotchas": ["Not a single centralized program—network of independent centers with varying eligibility (e.g., no dementia at some); often confused with employment training (SCSEP, age 55+, job-focused) or Medicaid waivers; many free but some sliding scale/voluntary fees; priority for most-in-need in some services; must confirm center-specific rules as no uniform application.[1][4][5][9]", "Medical/functional needs assessed for advanced services, not automatic.", "Targeted groups like Hispanic seniors at Vida may have cultural/language focus others lack."],
  "data_shape_notes": "Decentralized network of centers/providers under D.C. Office on Aging, no uniform income/asset test for core social services, varies by provider (e.g., dementia exclusion, language-specific), employment/nutrition/waiver programs have stricter financial/functional criteria."
}

{
  "name": "Legal Services for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits stated; services target D.C. residents 60+ or 55+ with SSI/SSDI issues. Related providers like Legal Aid DC use 200-300% of Federal Poverty Guidelines, but not confirmed for this program.[1][2][6]",
    "asset_limits": "No asset limits or exemptions mentioned in sources.[1][2]",
    "other_requirements": ["Must be a resident of the District of Columbia.", "Priority for those with economic or social needs, abuse victims, public benefits issues, or disability-related matters (55+ for SSI/SSDI)."][1][2][3]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice, guidance, representation in administrative actions/proceedings by attorneys/paralegals; specific services include: victims of abuse, medical bills, advocacy, public benefits access (SS/SSI/SSDI, Medicaid, Medicare, SNAP, veterans benefits), drafting wills, conservatorship/guardianship, advance directives, housing/eviction/foreclosure, long-term care, elder rights protections, consumer fraud, financial exploitation; also notary public service and Legal Hotline for advice/referrals/representation intake.[1][2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone: AARP Legal Counsel for the Elderly (202) 434-2120; DACL/DC Office on Aging (202) 724-5626; TTY 711.[1][2]",
      "Website: https://www.aarp.org/legal-counsel-for-elderly/ for Legal Hotline and services; https://dacl.dc.gov/service/legal-services-seniors.[1][2]",
      "In-person: AARP Legal Counsel for the Elderly at 601 E Street, NW, Room A-4, Washington, DC 20049; DC Office on Aging Notary at 500 K Street, NE, Washington, DC 20002 (Mon-Fri 8:30am-4pm).[1]",
      "Email: [email protected]; Fax options available.[1]"
    ],
    "processing_time": "Not specified; Legal Hotline offers quick access to advice, referrals, and intake.[2]",
    "waitlist": "No waitlist information provided.[1][2]",
    "forms": ["No specific form names/numbers listed; online intake application may apply via related providers like Legal Aid DC.[6]"],
    "documents": ["Documents related to legal problem if available (e.g., for income/household screening or case specifics); not mandatory for initial hotline/advice.[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "District of Columbia residents only.",
    "regional_variations": "No regional variations mentioned; DC-wide program with central offices.[1][2]",
    "offices_or_providers": ["AARP Legal Counsel for the Elderly (601 E Street NW), DC Office on Aging (500 K Street NE)."][1]
  },
  "official_source": "https://dacl.dc.gov/service/legal-services-seniors",
  "gotchas": [
    "No explicit income/asset dollar limits published; families must contact providers for screening (e.g., may align with 200-300% FPL via partners).[6]",
    "Age 55+ only for specific SSI/SSDI issues; otherwise 60+.[2]",
    "Services are advice/representation focused, not financial aid; may refer for benefits enrollment.[1][3]",
    "Funded under Older Americans Act, targeting economic/social needs—may prioritize high-need cases.[3]"
  ],
  "data_shape_notes": "No fixed income/asset tables; eligibility primarily age/residency-based with priority tiers for needs like abuse or benefits; delivered via specific DC providers like AARP LCE, no county variations as DC is single jurisdiction."
}
